                                Text(locationName)
                                    .font(.custom("DM Mono", size: 10))
                            }
                            .foregroundColor(ClipBetColors.textFaint)
                        }
                    }
                    .padding(.horizontal, 24)
                    .padding(.vertical, 24)

                    ClipBetDivider()

                    // QR Code
                    VStack(spacing: 16) {
                        QRCodeView(url: qrURL, size: 180)
