//  ClipBetModels.swift
//  ClipBet
//
//  Data models for events, bets, organizers, and outcomes.
//  Based on the full backend schema (Part 8).
//

import Foundation
import SwiftUI

// MARK: - Design System Colors

enum ClipBetColors {
    static let bg           = Color(white: 0.98) // Off-white
    static let surface      = Color(white: 0.94)
    static let divider      = Color(white: 0.90)
    static let textPrimary  = Color(white: 0.12) // Softer off-black
    static let textSecondary = Color(white: 0.45)
    static let textFaint    = Color(white: 0.65)

    static let yes          = Color(red: 100/255, green: 170/255, blue: 140/255)
    static let yesFill      = Color(red: 220/255, green: 240/255, blue: 230/255)
    static let no           = Color(red: 200/255, green: 100/255, blue: 100/255)
    static let noFill       = Color(red: 250/255, green: 225/255, blue: 225/255)
    static let accent       = Color(white: 0.25)

    static let dark         = Color(white: 0.10)
}

// MARK: - Event Status

enum EventStatus: String, CaseIterable {
    case planned = "PLANNED"
    case live = "LIVE"
    case betsClosed = "BETS CLOSED"
    case resolved = "RESOLVED"
    case cancelled = "CANCELLED"

    var dotColor: Color {
        switch self {
        case .planned:     return ClipBetColors.textSecondary
        case .live:        return ClipBetColors.accent
        case .betsClosed:  return ClipBetColors.textSecondary
        case .resolved:    return ClipBetColors.yes
        case .cancelled:   return ClipBetColors.textFaint
        }
    }

    var isPulsing: Bool {
        self == .live
    }
}

// MARK: - Betting Window

enum BettingWindow: String {
    case manual = "Close Manually"
    case atStart = "Close at Start"
    case stayOpen = "Stay Open During Event"
}

// MARK: - Bet Outcome (Option)

struct BetOutcome: Identifiable, Hashable {
    let id: UUID
    let name: String
    var totalAmount: Double
    var betCount: Int

    var formattedAmount: String {
        String(format: "$%.0f", totalAmount)
    }
}

// MARK: - Prediction Event

struct PredictionEvent: Identifiable {
    let id: UUID
    let name: String
    let description: String?
    let imageURL: String?
    var localImage: UIImage?
    let location: String
    let locationLat: Double
    let locationLng: Double
    let organizer: String
    let organizerId: UUID
    var status: EventStatus
    var outcomes: [BetOutcome]
    let minimumBet: Double
    let bettingWindow: BettingWindow
    let createdAt: Date
    var eventTime: Date?
    var eventEndTime: Date?
    var startedAt: Date?
    var closedAt: Date?
    var resolvedAt: Date?
    var resolvedOutcomeId: UUID?

    // MARK: - Event State

    var isExpired: Bool {
        status == .resolved || status == .cancelled
    }

    var isAcceptingBets: Bool {
        status == .live
    }

    var isPlanned: Bool {
        status == .planned
    }

    // MARK: - Pool Calculations

    var totalPool: Double {
        outcomes.reduce(0) { $0 + $1.totalAmount }
    }

    var totalBettors: Int {
        outcomes.reduce(0) { $0 + $1.betCount }
    }

    var platformFee: Double {
        totalPool * 0.05
    }

    var winnerPool: Double {
        totalPool - platformFee
    }

    func percentage(for outcome: BetOutcome) -> Double {
        guard totalPool > 0 else { return 0 }
        return (outcome.totalAmount / totalPool) * 100
    }

    func estimatedReturn(betAmount: Double, for outcome: BetOutcome) -> Double {
        let newOutcomeTotal = outcome.totalAmount + betAmount
        let newPoolTotal = totalPool + betAmount
        let winnerPoolAfterFee = newPoolTotal * 0.95
        return (betAmount / newOutcomeTotal) * winnerPoolAfterFee
    }

    var formattedPool: String {
        String(format: "$%.0f", totalPool)
    }

    var formattedEventTime: String? {
        guard let eventTime else { return nil }
        let formatter = DateFormatter()
        formatter.dateFormat = "MMM d, h:mm a"
        return formatter.string(from: eventTime)
    }

    var timeSinceCreated: String {
        // For planned events, show time until start
        if let eventTime, status == .planned {
            let interval = eventTime.timeIntervalSince(Date())
            if interval > 0 {
                let minutes = Int(interval) / 60
                let hours = minutes / 60
                if hours > 0 {
                    return "starts in \(hours)h \(minutes % 60)m"
                }
                return "starts in \(minutes)m"
            }
        }
        let interval = Date().timeIntervalSince(createdAt)
        let minutes = Int(interval) / 60
        let hours = minutes / 60
        if hours > 0 {
            return "\(hours)h \(minutes % 60)m"
        }
        return "\(minutes)m"
    }
}

// MARK: - Bet Status

enum BetStatus: String {
    case pending = "Pending"
    case confirmed = "Confirmed"
    case won = "Won"
    case lost = "Lost"
    case refunded = "Refunded"
}

// MARK: - Payout Status

enum PayoutStatus: String {
    case none = "None"
    case processing = "Processing"
    case completed = "Completed"
    case failed = "Failed"
}

// MARK: - User Bet

struct UserBet: Identifiable {
    let id: UUID
    let eventId: UUID
    let outcomeId: UUID
    let amount: Double
    let nickname: String
    let email: String
    var status: BetStatus
    var payoutAmount: Double?
    var payoutStatus: PayoutStatus
    let createdAt: Date
    var stripePaymentIntentId: String?
}

// MARK: - Organizer

struct EventOrganizer: Identifiable {
    let id: UUID
    let appleUserId: String
    var stripeConnectId: String?
    let tosAgreedAt: Date?
    let verifiedAt: Date?
    var eventsCreated: Int
    var disputesAgainst: Int
    var rating: Double

    var isVerified: Bool {
        verifiedAt != nil && stripeConnectId != nil
    }

    var isFirstTime: Bool {
        tosAgreedAt == nil
    }
}

// MARK: - Dispute

enum DisputeStatus: String {
    case open = "Open"
    case resolved = "Resolved"
    case rejected = "Rejected"
}

struct BetDispute: Identifiable {
    let id: UUID
    let eventId: UUID
    let bettorId: UUID
    let reason: String
    var status: DisputeStatus
    let createdAt: Date
    var resolvedAt: Date?
    var resolution: String?
}

// MARK: - From Submissions/clipbet/ClipBetNetworking.swift

//  ClipBetNetworking.swift
//  ClipBet
//
//  API client for ClipBet backend.
//  All calls go through URLSession to the Express + Supabase + Stripe backend.
//  Set useMockData = true for simulator demo without backend.
//

import Foundation

// MARK: - API Configuration

enum ClipBetAPIConfig {
    /// Toggle to use mock data instead of real API calls
    static var useMockData = true

    /// Backend URL — set to your Railway/local deployment
    static var baseURL = "http://localhost:3001"
}

// MARK: - API Response Types

struct EventResponse: Decodable {
    let event: APIEvent
    let qr_url: String?
}

struct SingleEventResponse: Decodable {
    let event: APIEvent
}

struct PlaceBetResponse: Decodable {
    let bet_id: String
    let client_secret: String
    let payment_intent_id: String
}

struct SignInResponse: Decodable {
    let organizer: APIOrganizer
    let is_new: Bool
    let needs_tos: Bool
    let needs_stripe: Bool
}

struct ResolveResponse: Decodable {
    let status: String
    let total_pool: Double
    let platform_fee: Double
    let winner_pool: Double
    let winners: Int
    let losers: Int
}

struct CancelResponse: Decodable {
    let status: String
    let refunded_bets: Int
}

// MARK: - API Models (snake_case from backend)

struct APIEvent: Decodable {
    let id: String
    let name: String
    let description: String?
    let image_url: String?
    let status: String
    let minimum_bet: Double?
    let betting_window: String?
    let organizer_id: String
    let location_lat: Double?
    let location_lng: Double?
    let location_name: String?
    let event_time: String?
    let event_end_time: String?
    let total_pool: Double?
    let platform_fee: Double?
    let winner_pool: Double?
    let winning_option_id: String?
    let created_at: String
    let started_at: String?
    let closed_at: String?
    let resolved_at: String?
    let options: [APIOption]?
    let organizers: APIOrganizer?
}

struct APIOption: Decodable {
    let id: String
    let event_id: String
    let name: String
    let total_bets: Int?
    let total_amount: Double?
    let percentage: Double?
}

struct APIOrganizer: Decodable {
    let id: String
    let rating: Double?
    let events_created: Int?
    let apple_user_id: String?
    let stripe_connect_id: String?
    let tos_agreed_at: String?
    let verified_at: String?
}

// MARK: - API Client

final class ClipBetAPI {

    static let shared = ClipBetAPI()
    private init() {}

    private let decoder: JSONDecoder = {
        let d = JSONDecoder()
        return d
    }()

    private let isoFormatter: ISO8601DateFormatter = {
        let f = ISO8601DateFormatter()
        f.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        return f
    }()

    // MARK: - Fetch Event

    func fetchEvent(id: String, completion: @escaping (Result<PredictionEvent, Error>) -> Void) {
        if ClipBetAPIConfig.useMockData {
            completion(.success(ClipBetMockData.primaryEvent))
            return
        }

        let url = URL(string: "\(ClipBetAPIConfig.baseURL)/events/\(id)")!
        var request = URLRequest(url: url)
        request.httpMethod = "GET"

        URLSession.shared.dataTask(with: request) { [weak self] data, _, error in
            guard let self else { return }
            if let error {
                DispatchQueue.main.async { completion(.failure(error)) }
                return
            }
            guard let data else {
                DispatchQueue.main.async { completion(.failure(APIError.noData)) }
                return
            }
            do {
                let response = try self.decoder.decode(SingleEventResponse.self, from: data)
                let event = self.mapEvent(response.event)
                DispatchQueue.main.async { completion(.success(event)) }
            } catch {
                DispatchQueue.main.async { completion(.failure(error)) }
            }
        }.resume()
    }

    // MARK: - Create Event

    func createEvent(
        name: String,
        description: String?,
        imageURL: String?,
        options: [String],
        minimumBet: Double,
        organizerId: String,
        locationName: String?,
        locationLat: Double?,
        locationLng: Double?,
        eventTime: Date?,
        completion: @escaping (Result<(PredictionEvent, String), Error>) -> Void
    ) {
        if ClipBetAPIConfig.useMockData {
            let mockId = UUID()
            var mockEvent = ClipBetMockData.primaryEvent
            // Override with user input for mock
            let event = PredictionEvent(
                id: mockId,
                name: name,
                description: description,
                imageURL: imageURL,
                location: locationName ?? "Unknown",
                locationLat: locationLat ?? 0,
                locationLng: locationLng ?? 0,
                organizer: "You",
                organizerId: UUID(),
                status: .live,
                outcomes: options.map { BetOutcome(id: UUID(), name: $0, totalAmount: 0, betCount: 0) },
                minimumBet: minimumBet,
                bettingWindow: .manual,
                createdAt: Date(),
                eventTime: eventTime
            )
            let qrURL = "clipbet.io/event/\(mockId.uuidString.prefix(8).lowercased())"
            completion(.success((event, qrURL)))
            return
        }

        let url = URL(string: "\(ClipBetAPIConfig.baseURL)/events")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        var body: [String: Any] = [
            "name": name,
            "options": options,
            "minimum_bet": minimumBet,
            "organizer_id": organizerId,
        ]
        if let description { body["description"] = description }
        if let imageURL { body["image_url"] = imageURL }
        if let locationName { body["location_name"] = locationName }
        if let locationLat { body["location_lat"] = locationLat }
        if let locationLng { body["location_lng"] = locationLng }
        if let eventTime { body["event_time"] = ISO8601DateFormatter().string(from: eventTime) }

        request.httpBody = try? JSONSerialization.data(withJSONObject: body)

        URLSession.shared.dataTask(with: request) { [weak self] data, _, error in
            guard let self else { return }
            if let error {
                DispatchQueue.main.async { completion(.failure(error)) }
                return
            }
            guard let data else {
                DispatchQueue.main.async { completion(.failure(APIError.noData)) }
                return
            }
            do {
                let response = try self.decoder.decode(EventResponse.self, from: data)
                let event = self.mapEvent(response.event)
                let qrURL = response.qr_url ?? "clipbet.io/event/\(response.event.id)"
                DispatchQueue.main.async { completion(.success((event, qrURL))) }
            } catch {
                DispatchQueue.main.async { completion(.failure(error)) }
            }
        }.resume()
    }

    // MARK: - Place Bet

    func placeBet(
        eventId: String,
        optionId: String,
        amount: Double,
        email: String,
        nickname: String,
        completion: @escaping (Result<PlaceBetResponse, Error>) -> Void
    ) {
        if ClipBetAPIConfig.useMockData {
            let mock = PlaceBetResponse(
                bet_id: UUID().uuidString,
                client_secret: "pi_mock_\(UUID().uuidString.prefix(8))_secret",
                payment_intent_id: "pi_mock_\(UUID().uuidString.prefix(8))"
            )
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
                completion(.success(mock))
            }
            return
        }

        let url = URL(string: "\(ClipBetAPIConfig.baseURL)/events/\(eventId)/bets")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let body: [String: Any] = [
            "option_id": optionId,
            "amount": amount,
            "email": email,
            "nickname": nickname,
        ]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)

        URLSession.shared.dataTask(with: request) { [weak self] data, _, error in
            guard let self else { return }
            if let error {
                DispatchQueue.main.async { completion(.failure(error)) }
                return
            }
            guard let data else {
                DispatchQueue.main.async { completion(.failure(APIError.noData)) }
                return
            }
            do {
                let response = try self.decoder.decode(PlaceBetResponse.self, from: data)
                DispatchQueue.main.async { completion(.success(response)) }
            } catch {
                DispatchQueue.main.async { completion(.failure(error)) }
            }
        }.resume()
    }

    // MARK: - Close Bets

    func closeBets(eventId: String, completion: @escaping (Result<Void, Error>) -> Void) {
        if ClipBetAPIConfig.useMockData {
            completion(.success(()))
            return
        }
        patchStatus(eventId: eventId, status: "bets_closed", completion: completion)
    }

    // MARK: - Resolve Event

    func resolveEvent(
        eventId: String,
        winningOptionId: String,
        organizerId: String,
        completion: @escaping (Result<Void, Error>) -> Void
    ) {
        if ClipBetAPIConfig.useMockData {
            completion(.success(()))
            return
        }

        let url = URL(string: "\(ClipBetAPIConfig.baseURL)/organizers/events/\(eventId)/resolve")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let body: [String: Any] = [
            "winning_option_id": winningOptionId,
            "organizer_id": organizerId,
        ]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)

        URLSession.shared.dataTask(with: request) { data, _, error in
            if let error {
                DispatchQueue.main.async { completion(.failure(error)) }
                return
            }
            DispatchQueue.main.async { completion(.success(())) }
        }.resume()
    }

    // MARK: - Cancel Event

    func cancelEvent(
        eventId: String,
        organizerId: String,
        completion: @escaping (Result<Void, Error>) -> Void
    ) {
        if ClipBetAPIConfig.useMockData {
            completion(.success(()))
            return
        }

        let url = URL(string: "\(ClipBetAPIConfig.baseURL)/organizers/events/\(eventId)/cancel")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let body: [String: Any] = ["organizer_id": organizerId]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)

        URLSession.shared.dataTask(with: request) { data, _, error in
            if let error {
                DispatchQueue.main.async { completion(.failure(error)) }
                return
            }
            DispatchQueue.main.async { completion(.success(())) }
        }.resume()
    }

    // MARK: - Sign In Organizer

    func signinOrganizer(
        appleUserId: String,
        completion: @escaping (Result<SignInResponse, Error>) -> Void
    ) {
        if ClipBetAPIConfig.useMockData {
            let mock = SignInResponse(
                organizer: APIOrganizer(
                    id: UUID().uuidString,
                    rating: 5.0,
                    events_created: 0,
                    apple_user_id: appleUserId,
                    stripe_connect_id: nil,
                    tos_agreed_at: nil,
                    verified_at: nil
                ),
                is_new: true,
                needs_tos: true,
                needs_stripe: true
            )
            completion(.success(mock))
            return
        }

        let url = URL(string: "\(ClipBetAPIConfig.baseURL)/organizers/signin")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = try? JSONSerialization.data(
            withJSONObject: ["apple_user_id": appleUserId]
        )

        URLSession.shared.dataTask(with: request) { [weak self] data, _, error in
            guard let self else { return }
            if let error {
                DispatchQueue.main.async { completion(.failure(error)) }
                return
            }
            guard let data else {
                DispatchQueue.main.async { completion(.failure(APIError.noData)) }
                return
            }
            do {
                let response = try self.decoder.decode(SignInResponse.self, from: data)
                DispatchQueue.main.async { completion(.success(response)) }
            } catch {
                DispatchQueue.main.async { completion(.failure(error)) }
            }
        }.resume()
    }

    // MARK: - Helpers

    private func patchStatus(eventId: String, status: String, completion: @escaping (Result<Void, Error>) -> Void) {
        let url = URL(string: "\(ClipBetAPIConfig.baseURL)/events/\(eventId)/status")!
        var request = URLRequest(url: url)
        request.httpMethod = "PATCH"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = try? JSONSerialization.data(withJSONObject: ["status": status])

        URLSession.shared.dataTask(with: request) { data, _, error in
            if let error {
                DispatchQueue.main.async { completion(.failure(error)) }
                return
            }
            DispatchQueue.main.async { completion(.success(())) }
        }.resume()
    }

    private func parseDate(_ string: String?) -> Date? {
        guard let string else { return nil }
        return isoFormatter.date(from: string)
    }

    func mapEvent(_ api: APIEvent) -> PredictionEvent {
        let outcomes = (api.options ?? []).map { opt in
            BetOutcome(
                id: UUID(uuidString: opt.id) ?? UUID(),
                name: opt.name,
                totalAmount: opt.total_amount ?? 0,
                betCount: opt.total_bets ?? 0
            )
        }

        let status: EventStatus = {
            switch api.status {
            case "planned": return .planned
            case "live": return .live
            case "bets_closed": return .betsClosed
            case "resolved": return .resolved
            case "cancelled": return .cancelled
            default: return .live
            }
        }()

        return PredictionEvent(
            id: UUID(uuidString: api.id) ?? UUID(),
            name: api.name,
            description: api.description,
            imageURL: api.image_url,
            location: api.location_name ?? "Unknown Location",
            locationLat: api.location_lat ?? 0,
            locationLng: api.location_lng ?? 0,
            organizer: api.organizers?.apple_user_id ?? "Organizer",
            organizerId: UUID(uuidString: api.organizer_id) ?? UUID(),
            status: status,
            outcomes: outcomes,
            minimumBet: api.minimum_bet ?? 5,
            bettingWindow: .manual,
            createdAt: parseDate(api.created_at) ?? Date(),
            eventTime: parseDate(api.event_time),
            eventEndTime: parseDate(api.event_end_time),
            startedAt: parseDate(api.started_at),
            closedAt: parseDate(api.closed_at),
            resolvedAt: parseDate(api.resolved_at),
            resolvedOutcomeId: api.winning_option_id.flatMap { UUID(uuidString: $0) }
        )
    }
}

// MARK: - API Error

enum APIError: LocalizedError {
    case noData
    case invalidResponse
    case serverError(String)

    var errorDescription: String? {
        switch self {
        case .noData: return "No data received"
        case .invalidResponse: return "Invalid response"
        case .serverError(let msg): return msg
        }
    }
}

// MARK: - From Submissions/clipbet/ClipBetPayment.swift

//  ClipBetPayment.swift
//  ClipBet
//
//  Payment manager handling Apple Pay (user-facing) with
//  Stripe as the invisible backend. Users never see Stripe.
//
//  In production:
//    Apple Pay -> PKPaymentRequest -> Stripe PaymentIntent -> Escrow
//    Resolve -> Stripe Connect transfers to winners
//    Cancel -> Stripe refunds to original payment methods
//
//  For hackathon demo: fully mocked with realistic states.
//

import SwiftUI

// MARK: - Payment State

enum PaymentState: Equatable {
    case idle
    case processing
    case success(transactionId: String)
    case failed(message: String)
    case refunded
}

// MARK: - Payment Method

enum PaymentMethod: String {
    case applePay = "Apple Pay"
    case card = "Card"
}

// MARK: - Escrow State

enum EscrowState: String {
    case pending = "Pending"
    case held = "Held"
    case distributing = "Distributing"
    case distributed = "Distributed"
    case refunding = "Refunding"
    case refunded = "Refunded"
}

// MARK: - Payment Manager

@Observable
final class ClipBetPaymentManager {

    var paymentState: PaymentState = .idle
    var selectedMethod: PaymentMethod = .applePay
    var escrowState: EscrowState = .pending

    // In production this would be the Stripe PaymentIntent ID
    private(set) var paymentIntentId: String?

    // Platform fee percentage
    let platformFeeRate: Double = 0.05

    /// Processes a bet payment. In production this would:
    /// 1. Create a Stripe PaymentIntent on the backend
    /// 2. Present Apple Pay sheet (PKPaymentAuthorizationViewController)
    /// 3. Confirm the PaymentIntent with the Apple Pay token
    /// 4. Hold funds in escrow on the platform Stripe account
    func processBet(
        amount: Double,
        eventId: UUID,
        outcomeId: UUID,
        email: String,
        nickname: String,
        completion: @escaping (Bool) -> Void
    ) {
        paymentState = .processing

        if !ClipBetAPIConfig.useMockData {
            // Real API: get Stripe client_secret from backend
            ClipBetAPI.shared.placeBet(
                eventId: eventId.uuidString,
                optionId: outcomeId.uuidString,
                amount: amount,
                email: email,
                nickname: nickname
            ) { [weak self] result in
                guard let self else { return }
                switch result {
                case .success(let response):
                    // In production: use response.client_secret with PKPaymentRequest
                    // For hackathon: mark as success directly
                    self.paymentIntentId = response.payment_intent_id
                    self.paymentState = .success(transactionId: response.payment_intent_id)
                    self.escrowState = .held
                    completion(true)
                case .failure(let error):
                    self.paymentState = .failed(message: error.localizedDescription)
                    completion(false)
                }
            }
            return
        }

        // Mock: simulate network delay for PaymentIntent creation + Apple Pay
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) { [weak self] in
            guard let self else { return }

            // Simulate 95% success rate
            let success = Double.random(in: 0...1) < 0.95

            if success {
                let txId = "pi_\(UUID().uuidString.prefix(8))"
                self.paymentIntentId = txId
                self.paymentState = .success(transactionId: txId)
                self.escrowState = .held
                completion(true)
            } else {
                self.paymentState = .failed(message: "Payment could not be completed. Please try again.")
                completion(false)
            }
        }
    }

    // MARK: - Distribute Winnings

    /// Called when organizer resolves the event. In production:
    /// 1. Backend calculates each winner's share
    /// 2. Deducts 5% platform fee
    /// 3. Creates Stripe Connect transfers to winner payment methods
    /// 4. Organizer gets their fee share via Stripe Connect
    func distributeWinnings(
        event: PredictionEvent,
        winningOutcomeId: UUID,
        completion: @escaping ([(nickname: String, payout: Double)]) -> Void
    ) {
        escrowState = .distributing

        DispatchQueue.main.asyncAfter(deadline: .now() + 2.0) { [weak self] in
            guard let self else { return }
            guard let winningOutcome = event.outcomes.first(where: { $0.id == winningOutcomeId }) else {
                return
            }

            let totalPool = event.totalPool
            let fee = totalPool * self.platformFeeRate
            let winnerPool = totalPool - fee

            // Parimutuel: each winner gets proportional share
            // In production, each individual bet amount is tracked
            let payoutPerDollar = winnerPool / winningOutcome.totalAmount

            // Mock payout list
            let payouts: [(nickname: String, payout: Double)] = [
                ("Winner1", 25.0 * payoutPerDollar),
                ("Winner2", 10.0 * payoutPerDollar),
            ]

            self.escrowState = .distributed
            completion(payouts)
        }
    }

    // MARK: - Process Refund

    /// Called when organizer cancels or 24h resolution window expires.
    /// In production: triggers Stripe refunds to original payment methods.
    func processRefund(completion: @escaping (Bool) -> Void) {
        escrowState = .refunding

        DispatchQueue.main.asyncAfter(deadline: .now() + 1.0) { [weak self] in
            self?.escrowState = .refunded
            self?.paymentState = .refunded
            completion(true)
        }
    }

    // MARK: - Reset

    func reset() {
        paymentState = .idle
        paymentIntentId = nil
        escrowState = .pending
    }
}

// MARK: - Apple Pay Button View

struct ClipBetApplePayButton: View {
    let amount: Double
    let isEnabled: Bool
    let isProcessing: Bool
    let onTap: () -> Void
    let onCardFallback: () -> Void

    var body: some View {
        VStack(spacing: 12) {
            // Primary: Apple Pay
            Button(action: onTap) {
                HStack(spacing: 8) {
                    if isProcessing {
                        ProgressView()
                            .tint(ClipBetColors.dark)
                    } else {
                        Image(systemName: "apple.logo")
                            .font(.system(size: 18))
                        Text("PAY WITH APPLE PAY")
                            .font(.custom("DM Mono", size: 13))
                            .kerning(2)
                    }
                }
                .foregroundColor(ClipBetColors.dark)
                .frame(maxWidth: .infinity)
                .padding(.vertical, 18)
                .background(Color.white)
                .clipShape(RoundedRectangle(cornerRadius: 2))
            }
            .disabled(!isEnabled || isProcessing)
            .opacity(isEnabled ? 1.0 : 0.5)

            // Fallback: Pay with card (still Stripe underneath, no branding)
            Button(action: onCardFallback) {
                Text("or pay with card")
                    .font(.custom("DM Mono", size: 11))
                    .foregroundColor(ClipBetColors.textFaint)
                    .underline()
            }
            .disabled(!isEnabled || isProcessing)
        }
    }
}

// MARK: - Payment Status View

struct ClipBetPaymentStatus: View {
    let state: PaymentState

    var body: some View {
        switch state {
        case .idle:
            EmptyView()

        case .processing:
            HStack(spacing: 8) {
                ProgressView()
                    .tint(ClipBetColors.textSecondary)
                Text("PROCESSING")
                    .font(.custom("DM Mono", size: 10))
                    .kerning(1.6)
                    .foregroundColor(ClipBetColors.textSecondary)
            }
            .padding(.vertical, 8)

        case .success(let txId):
            VStack(spacing: 4) {
                HStack(spacing: 6) {
                    Image(systemName: "checkmark.circle.fill")
                        .font(.system(size: 12))
                        .foregroundColor(ClipBetColors.yes)
                    Text("PAYMENT CONFIRMED")
                        .font(.custom("DM Mono", size: 10))
                        .kerning(1.6)
                        .foregroundColor(ClipBetColors.yes)
                }
                Text(txId)
                    .font(.custom("DM Mono", size: 9))
                    .foregroundColor(ClipBetColors.textFaint)
            }
            .padding(.vertical, 8)

        case .failed(let message):
            VStack(spacing: 4) {
                HStack(spacing: 6) {
                    Image(systemName: "xmark.circle.fill")
                        .font(.system(size: 12))
                        .foregroundColor(ClipBetColors.no)
                    Text("PAYMENT FAILED")
                        .font(.custom("DM Mono", size: 10))
                        .kerning(1.6)
                        .foregroundColor(ClipBetColors.no)
                }
                Text(message)
                    .font(.custom("DM Mono", size: 10))
                    .foregroundColor(ClipBetColors.textSecondary)
                    .multilineTextAlignment(.center)
            }
            .padding(.vertical, 8)

        case .refunded:
            HStack(spacing: 6) {
                Image(systemName: "arrow.uturn.backward.circle.fill")
                    .font(.system(size: 12))
                    .foregroundColor(ClipBetColors.textSecondary)
                Text("REFUNDED")
                    .font(.custom("DM Mono", size: 10))
                    .kerning(1.6)
                    .foregroundColor(ClipBetColors.textSecondary)
            }
            .padding(.vertical, 8)
        }
    }
}

